+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+export type WindowBoundary =
+	| { type: 'unbounded preceding' | 'current row' | 'unbounded following' }
+	| { type: 'preceding' | 'following'; value: number };
+
+export const unboundedPreceding: WindowBoundary = { type: 'unbounded preceding' };
+export const currentRow: WindowBoundary = { type: 'current row' };
+export const unboundedFollowing: WindowBoundary = { type: 'unbounded following' };
+
+function offsetBoundary(type: 'preceding' | 'following', value: number): WindowBoundary {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${type}() requires a non-negative integer; received ${value}`);
+	}
+	return { type, value };
+}
+
+export function preceding(value: number): WindowBoundary {
+	return offsetBoundary('preceding', value);
+}
+
+export function following(value: number): WindowBoundary {
+	return offsetBoundary('following', value);
+}
+
+export interface WindowFrame {
+	type: 'rows' | 'range';
+	from: WindowBoundary;
+	to: WindowBoundary;
+}
+
+const boundaryOrder = (boundary: WindowBoundary): number => {
+	switch (boundary.type) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.value;
+		case 'current row': return 0;
+		case 'following': return boundary.value;
+		case 'unbounded following': return Infinity;
+	}
+};
+
+function frame(type: WindowFrame['type'], spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (boundaryOrder(spec.from) > boundaryOrder(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	return 'value' in boundary ? sql.raw(`${boundary.value} ${boundary.type}`) : sql.raw(boundary.type);
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy === undefined ? [] : Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
+	const orderBy = spec.orderBy === undefined ? [] : Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy];
+	const partitionSql = partitionBy.length ? sql`partition by ${sql.join(partitionBy, sql`, `)}` : undefined;
+	const orderSql = orderBy.length ? sql`order by ${sql.join(orderBy, sql`, `)}` : undefined;
+	const frameSql = spec.frame
+		? sql`${sql.raw(spec.frame.type)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}`
+		: undefined;
+	return sql.join([partitionSql, orderSql, frameSql].filter((part): part is SQL => part !== undefined), sql` `);
+}
+
+export function validateWindowName(name: string): void {
+	if (name.length === 0) throw new Error('Window name must be non-empty');
+	if (name.trim().length === 0) throw new Error('Window name must not be whitespace-only');
+}
+
+export class WindowFunction<T> extends SQL<T> {
+	over(spec: WindowSpec): SQL<T>;
+	over(name: string): SQL<T>;
+	over(specOrName: WindowSpec | string): SQL<T> {
+		return typeof specOrName === 'string'
+			? sql`${this} over ${sql.identifier(specOrName)}`
+			: sql`${this} over (${buildWindowSpec(specOrName)})`;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> {
+	return new WindowFunction<T>([sql.raw(name), sql.raw('('), sql.join(args, sql`, `), sql.raw(')')]);
+}
+
+function positiveInteger(functionName: string, value: number): void {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${functionName}() requires a positive integer; received ${value}`);
+	}
+}
+
+function position(value: number): SQL {
+	return sql.raw(String(value));
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number'); }
+export function rank(): WindowFunction<number> { return windowFunction('rank'); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank'); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank'); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist'); }
+export function ntile(buckets: number): WindowFunction<number> {
+	positiveInteger('ntile', buckets);
+	return windowFunction('ntile', [position(buckets)]);
+}
+
+export function lag<T extends SQLWrapper>(value: T): WindowFunction<(T extends AnyColumn ? T['_']['data'] : unknown) | null>;
+export function lag<T extends SQLWrapper>(value: T, offset: number): WindowFunction<(T extends AnyColumn ? T['_']['data'] : unknown) | null>;
+export function lag<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<T extends AnyColumn ? T['_']['data'] : unknown>;
+export function lag(value: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	return windowFunction('lag', [value, ...(offset === undefined ? [] : [position(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]);
+}
+
+export function lead<T extends SQLWrapper>(value: T): WindowFunction<(T extends AnyColumn ? T['_']['data'] : unknown) | null>;
+export function lead<T extends SQLWrapper>(value: T, offset: number): WindowFunction<(T extends AnyColumn ? T['_']['data'] : unknown) | null>;
+export function lead<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<T extends AnyColumn ? T['_']['data'] : unknown>;
+export function lead(value: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> {
+	return windowFunction('lead', [value, ...(offset === undefined ? [] : [position(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]);
+}
+
+export function firstValue<T extends SQLWrapper>(value: T): WindowFunction<(T extends AnyColumn ? T['_']['data'] : unknown) | null> { return windowFunction('first_value', [value]); }
+export function lastValue<T extends SQLWrapper>(value: T): WindowFunction<(T extends AnyColumn ? T['_']['data'] : unknown) | null> { return windowFunction('last_value', [value]); }
+export function nthValue<T extends SQLWrapper>(value: T, n: number): WindowFunction<(T extends AnyColumn ? T['_']['data'] : unknown) | null> {
+	positiveInteger('nthValue', n);
+	return windowFunction('nth_value', [value, position(n)]);
+}
+
+export function windowSum(value: SQLWrapper): WindowFunction<string | null> { return windowFunction('sum', [value]); }
+export function windowAvg(value: SQLWrapper): WindowFunction<string | null> { return windowFunction('avg', [value]); }
+export function windowMin<T extends SQLWrapper>(value: T): WindowFunction<(T extends AnyColumn ? T['_']['data'] : string) | null> { return windowFunction('min', [value]); }
+export function windowMax<T extends SQLWrapper>(value: T): WindowFunction<(T extends AnyColumn ? T['_']['data'] : string) | null> { return windowFunction('max', [value]); }
+export function windowCount(value?: SQLWrapper): WindowFunction<number> { return windowFunction('count', value ? [value] : [sql.raw('*')]); }
